@startuml
skinparam classAttributeIconSize 0
skinparam class {
  BackgroundColor #F5F5F5
  BorderColor Black
  ArrowColor Black
}
skinparam stereotypeCBackgroundColor #C8E6C9
skinparam stereotypeABackgroundColor #B2DFDB

class Subject {
  + observerCollection
  + RegisterObserver(observer)
  + UnregisterObserver(observer)
  + NotifyObservers()
}

class Observer {
  + Notify()
}

class ConcreteObserverA {
  + Notify()
}

class ConcreteObserverB {
  + Notify()
}

Subject "1" *-- "0..*" Observer : contains
Observer <|-- ConcreteObserverA
Observer <|-- ConcreteObserverB

note top of Subject
  <b>C</b>
end note

note top of Observer
  <b>A</b>
end note

note top of ConcreteObserverA
  <b>C</b>
end note

note top of ConcreteObserverB
  <b>C</b>
end note

@enduml
